<body>
    <h1>Maze Game with 24 Bots</h1>

    <div class="game-container">
        <div id="hud">
            <div class="hud-item">
                <span class="hud-label">Completed</span>
                <span class="hud-value" id="completed">0/24</span>
            </div>
            <div class="hud-item">
                <span class="hud-label">Time</span>
                <span class="hud-value" id="timer">0.0s</span>
            </div>
        </div>

        <div id="maze-container">
            <canvas id="maze"></canvas>
        </div>

        <button id="reset">Reset Game</button>
    </div>

    <script>
        // Maze generation and game logic
        class Maze {
            constructor(cols, rows) {
                this.cols = cols;
                this.rows = rows;
                this.grid = [];
                this.cellSize = 0;
                this.spawnCell = { x: 1, y: 1 };
                this.exitCell = { x: this.cols - 2, y: this.rows - 2 };
            }

            generate() {
                // Initialize grid with all walls (1)
                this.grid = [];
                for (let y = 0; y < this.rows; y++) {
                    const row = [];
                    for (let x = 0; x < this.cols; x++) {
                        row.push(1); // All walls initially
                    }
                    this.grid.push(row);
                }

                // Carve maze using recursive backtracking
                const stack = [];
                const startCell = { x: 1, y: 1 };
                this.grid[startCell.y][startCell.x] = 0; // Mark as visited (path)
                stack.push(startCell);

                while (stack.length > 0) {
                    const current = stack[stack.length - 1];
                    const neighbors = this.getUnvisitedNeighbors(current);

                    if (neighbors.length > 0) {
                        const next = neighbors[Math.floor(Math.random() * neighbors.length)];

                        // Remove wall between current and next
                        const wallX = (current.x + next.x) / 2;
                        const wallY = (current.y + next.y) / 2;
                        this.grid[wallY][wallX] = 0; // Remove wall
                        this.grid[next.y][next.x] = 0; // Mark as path

                        stack.push(next);
                    } else {
                        stack.pop();
                    }
                }

                // Ensure spawn and exit are clear
                this.grid[this.spawnCell.y][this.spawnCell.x] = 0;
                this.grid[this.exitCell.y][this.exitCell.x] = 0;
            }

            getUnvisitedNeighbors(cell) {
                const neighbors = [];
                const directions = [
                    { dx: 0, dy: -2 }, // Up
                    { dx: 2, dy: 0 },  // Right
                    { dx: 0, dy: 2 },  // Down
                    { dx: -2, dy: 0 }  // Left
                ];

                for (const dir of directions) {
                    const nx = cell.x + dir.dx;
                    const ny = cell.y + dir.dy;

                    if (nx > 0 && nx < this.cols - 1 && ny > 0 && ny < this.rows - 1 &&
                        this.grid[ny][nx] === 1) {
                        neighbors.push({ x: nx, y: ny });
                    }
                }

                return neighbors;
            }

            // BFS to find shortest path from start to end
            findPath(startX, startY, endX, endY) {
                const queue = [[{x: startX, y: startY}]];
                const visited = new Set();
                visited.add(`${startX},${startY}`);

                while (queue.length > 0) {
                    const path = queue.shift();
                    const cell = path[path.length - 1];

                    if (cell.x === endX && cell.y === endY) {
                        return path.slice(1); // Return path excluding start
                    }

                    const directions = [
                        { dx: 0, dy: -1 }, // Up
                        { dx: 1, dy: 0 },  // Right
                        { dx: 0, dy: 1 },  // Down
                        { dx: -1, dy: 0 }  // Left
                    ];

                    for (const dir of directions) {
                        const nx = cell.x + dir.dx;
                        const ny = cell.y + dir.dy;

                        if (nx >= 0 && nx < this.cols && ny >= 0 && ny < this.rows &&
                            this.grid[ny][nx] === 0 && !visited.has(`${nx},${ny}`)) {
                            visited.add(`${nx},${ny}`);
                            const newPath = [...path, {x: nx, y: ny}];
                            queue.push(newPath);
                        }
                    }
                }

                return []; // No path found
            }
        }

        class Bot {
            constructor(id, startX, startY) {
                this.id = id;
                this.x = startX;
                this.y = startY;
                this.path = [];
                this.pathIndex = 0;
                this.completed = false;
                this.spawnX = startX;
                this.spawnY = startY;
            }

            setPath(path) {
                this.path = path;
                this.pathIndex = 0;
            }

            move() {
                if (this.completed || this.path.length === 0) return;

                if (this.pathIndex < this.path.length) {
                    const nextCell = this.path[this.pathIndex];
                    this.x = nextCell.x;
                    this.y = nextCell.y;
                    this.pathIndex++;

                    // Check if reached exit
                    if (this.x === game.maze.exitCell.x && this.y === game.maze.exitCell.y) {
                        this.completed = true;
                    }
                }
            }

            reset() {
                this.x = this.spawnX;
                this.y = this.spawnY;
                this.pathIndex = 0;
                this.completed = false;
            }
        }

        class Game {
            constructor() {
                this.maze = new Maze(15, 15);
                this.bots = [];
                this.startTime = 0;
                this.elapsedMs = 0;
                this.isRunning = false;
                this.canvas = document.getElementById('maze');
                this.ctx = this.canvas.getContext('2d');

                // Set canvas size explicitly
                const size = 500;
                this.canvas.width = size;
                this.canvas.height = size;

                this.init();
            }

            init() {
                this.maze.generate();
                this.bots = [];

                // Create 24 bots with staggered start times
                for (let i = 0; i < 24; i++) {
                    const bot = new Bot(i, this.maze.spawnCell.x, this.maze.spawnCell.y);

                    // Calculate path to exit
                    const path = this.maze.findPath(
                        bot.spawnX, 
                        bot.spawnY, 
                        this.maze.exitCell.x, 
                        this.maze.exitCell.y
                    );
                    bot.setPath(path);

                    // Stagger start by adding random delay in path index
                    const staggerDelay = Math.floor(Math.random() * 5);
                    for (let j = 0; j < staggerDelay && bot.path.length > 0; j++) {
                        if (bot.pathIndex < bot.path.length) {
                            bot.pathIndex++;
                        }
                    }

                    this.bots.push(bot);
                }

                this.startTime = Date.now();
                this.elapsedMs = 0;
                this.isRunning = true;
                this.updateHUD();
            }

            tick(n) {
                // Advance simulation n steps
                for (let step = 0; step < n; step++) {
                    let activeBots = false;

                    for (const bot of this.bots) {
                        if (!bot.completed && bot.path.length > 0) {
                            bot.move();
                            activeBots = true;
                        }
                    }

                    // If no bots are active, stop early
                    if (!activeBots) break;
                }

                // Update elapsed time based on steps (assume each step is ~16ms)
                this.elapsedMs += n * 16;
                this.updateHUD();
            }

            updateHUD() {
                const completedCount = this.bots.filter(bot => bot.completed).length;
                document.getElementById('completed').textContent = `${completedCount}/24`;

                // Update timer display
                const elapsedSeconds = (this.elapsedMs / 1000).toFixed(1);
                document.getElementById('timer').textContent = `${elapsedSeconds}s`;
            }

            reset() {
                this.bots.forEach(bot => bot.reset());
                this.maze.generate();
                this.startTime = Date.now();
                this.elapsedMs = 0;

                // Recalculate paths for all bots
                for (const bot of this.bots) {
                    const path = this.maze.findPath(
                        bot.spawnX, 
                        bot.spawnY, 
                        this.maze.exitCell.x, 
                        this.maze.exitCell.y
                    );
                    bot.setPath(path);

                    // Stagger start by adding random delay in path index
                    const staggerDelay = Math.floor(Math.random() * 5);
                    for (let j = 0; j < staggerDelay && bot.path.length > 0; j++) {
                        if (bot.pathIndex < bot.path.length) {
                            bot.pathIndex++;
                        }
                    }
                }

                this.updateHUD();
            }

            draw() {
                const ctx = this.ctx;
                const canvasSize = this.canvas.width;
                const cellSize = canvasSize / this.maze.cols;

                // Clear canvas
                ctx.fillStyle = '#16213e';
                ctx.fillRect(0, 0, canvasSize, canvasSize);

                // Draw maze walls
                ctx.strokeStyle = '#4a90e2';
                ctx.lineWidth = 2;
                ctx.beginPath();

                for (let y = 0; y < this.maze.rows; y++) {
                    for (let x = 0; x < this.maze.cols; x++) {
                        if (this.maze.grid[y][x] === 1) {
                            // Draw wall
                            const px = x * cellSize;
                            const py = y * cellSize;

                            ctx.strokeRect(px, py, cellSize, cellSize);

                            // Add inner detail for better visual effect
                            ctx.fillStyle = '#2a4b7d';
                            ctx.fillRect(px + 1, py + 1, cellSize - 2, cellSize - 2);
                        }
                    }
                }

                // Draw spawn and exit areas
                const spawnX = this.maze.spawnCell.x * cellSize;
                const spawnY = this.maze.spawnCell.y * cellSize;
                ctx.fillStyle = 'rgba(76, 175, 80, 0.3)'; // Green for spawn
                ctx.fillRect(spawnX + 2, spawnY + 2, cellSize - 4, cellSize - 4);

                const exitX = this.maze.exitCell.x * cellSize;
                const exitY = this.maze.exitCell.y * cellSize;
                ctx.fillStyle = 'rgba(233, 69, 96, 0.3)'; // Red for exit
                ctx.fillRect(exitX + 2, exitY + 2, cellSize - 4, cellSize - 4);

                // Draw bots
                const colors = [
                    '#e94560', '#f0a830', '#4a90e2', '#7c4dff', 
                    '#00bcd4', '#ffeb3b', '#ff9800', '#8bc34a'
                ];

                for (let i = 0; i < this.bots.length; i++) {
                    const bot = this.bots[i];
                    const bx = bot.x * cellSize + cellSize / 2;
                    const by = bot.y * cellSize + cellSize / 2;

                    ctx.fillStyle = colors[i % colors.length];
                    ctx.beginPath();
                    ctx.arc(bx, by, cellSize / 3, 0, Math.PI * 2);
                    ctx.fill();

                    // Add glow effect for completed bots
                    if (bot.completed) {
                        ctx.strokeStyle = '#fff';
                        ctx.lineWidth = 2;
                        ctx.stroke();
                    }
                }
            }
        }

        // Initialize game and expose API
        const game = new Game();

        // Animation loop
        function animate() {
            if (game.isRunning) {
                game.draw();
                requestAnimationFrame(animate);
            }
        }

        // Start animation
        animate();

        // Expose game object on window as required
        window.game = {
            get bots() {
                return game.bots;
            },

            get completed() {
                return game.bots.filter(bot => bot.completed).length;
            },

            get elapsedMs() {
                return game.elapsedMs;
            },

            tick(n) {
                game.tick(n);
            },

            reset() {
                game.reset();
            }
        };

        // Event listeners
        document.getElementById('reset').addEventListener('click', () => {
            game.reset();
        });

        // Initial draw
        game.draw();
    </script>
</body>
</html>
